-- Luke Chapter 19
-- Theme: Salvation Received and Rejected: From Zacchaeus to the Cleansing of the Temple
-- 48 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 19,
  'Luke 19 is a chapter of arrivals — the arrival of salvation to Zacchaeus (vv.1-10), the arrival of accountability in the Parable of the Minas (vv.11-27), the arrival of the King in Jerusalem (vv.28-44), and the arrival of judgment in the Temple (vv.45-48). The chapter opens with the most personal of salvation encounters: Jesus stops in Jericho, looks up at a wealthy, despised tax collector in a tree, and announces that he must stay at his house today. Zacchaeus''s response — standing and declaring immediate, generous restitution — demonstrates the fruit of genuine conversion. Jesus''s declaration, "This day is salvation come to this house" (v.9), encapsulates Luke''s central soteriology.',
  'The Parable of the Minas (vv.11-27) is given specifically to correct the disciples'' expectation that the kingdom of God would immediately appear (v.11). It distinguishes between three categories: faithful servants who multiply the entrusted resources (rewarded with governance authority), unfaithful servants who preserve but do not invest (rebuked and stripped), and hostile citizens who reject the master''s kingship (executed). The parable''s political framework (a nobleman going to receive a kingdom while his citizens send an embassy of rejection) may reflect Archelaus''s trip to Rome in 4 BC; it serves to reframe kingdom expectations: the king departs, entrusts, then returns for accounting.',
  'The Triumphal Entry (vv.28-44) is Luke''s most distinctive version of the event, shaped by his theological concerns. The disciples'' praise — "Blessed be the King that cometh in the name of the Lord" (v.38) — is explicitly royal, citing Psalm 118:26. The Pharisees'' request to silence the disciples is met with Jesus''s declaration that if they were silent, the stones would cry out (v.40). But the entry reaches its emotional climax in the lament over Jerusalem (vv.41-44) — unique to Luke — where Jesus weeps (eklaien — imperfect: he kept weeping) over the city''s imminent destruction, which he attributes to its failure to recognize "the time of thy visitation" (v.44).',
  'The cleansing of the Temple (vv.45-48) is remarkably compressed in Luke compared to Mark and John. Jesus drives out the sellers and establishes a daily teaching ministry in the Temple — which will occupy chapters 20-21. The conflict over his authority (20:1-8) and the conspiracy to kill him (19:47; 20:19) are both introduced here, framing the Temple teaching as the penultimate act before the passion. The people''s hanging on his words (v.48: exekremato — hung suspended from his teaching, a vivid verb) and the chief priests'' inability to find a way to destroy him creates a temporary standoff that drives the passion narrative forward.',
  'σωτηρία (sōtēria)',
  'sōtēria means salvation, deliverance, rescue — the comprehensive word for God''s saving work. In v.9, "This day is salvation come to this house" (sēmeron sōtēria tō oikō toutō egeneto) — salvation arrives as a person, not merely a decision or a declaration; it comes to a household and is concretely demonstrated in Zacchaeus''s transformed relationship to money. The word gathers together the whole range of Luke''s soteriology: forgiveness (7:48-50), wholeness (8:48), sight (18:42), and now economic restitution. Salvation restructures every dimension of life, including the financial, and its arrival is dateable: "this day."',
  '["Zacchaeus: Salvation Comes to His House (vv.1-10)","The Parable of the Minas: Accountability at the King''s Return (vv.11-27)","The Triumphal Entry: The King Arrives (vv.28-40)","Jesus Weeps Over Jerusalem (vv.41-44)","Cleansing the Temple and Daily Teaching (vv.45-48)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'And Jesus entered and passed through Jericho.', 'Καὶ εἰσελθὼν διήρχετο τὴν Ἰεριχώ.', 'Kai eiselthōn diērcheto tēn Ierichō.', '"Entered and passed through Jericho" (eiselthōn diērcheto — having entered he was passing through) — the imperfect suggests a journey in progress, not a halt. Jericho was a prosperous city, the last major town before the ascent to Jerusalem. Verse 1 establishes the setting without fanfare; the significance of the stop will be revealed through what Jesus does rather than where he is. The brevity of the geographical note signals that what matters is not the city but the encounter about to occur.', NULL),
  (2, 'And, behold, there was a man named Zacchaeus, which was the chief among the publicans, and he was rich.', 'Καὶ ἰδοὺ ἀνὴρ ὀνόματι καλούμενος Ζακχαῖος, καὶ αὐτὸς ἦν ἀρχιτελώνης, καὶ αὐτὸς πλούσιος.', 'Kai idou anēr onomati kaloumenos Zakchaios, kai autos ēn architelōnēs, kai autos plousios.', '"Behold" (idou — see! a narrative attention signal) introduces the main character. "Zacchaeus" (Zakchaios — from the Hebrew Zaccai, meaning pure or innocent, a name ironically at odds with his profession). "Chief among the publicans" (architelōnēs — chief tax collector, a word found only here in all of Greek literature; arch = chief + telōnēs = tax collector) — a superintendent of tax collection, overseeing multiple collectors, hence doubly despised. "He was rich" — the identical characterization of the rich ruler (18:23: plousios sphodra); but Zacchaeus''s story will end entirely differently.', NULL),
  (3, 'And he sought to see Jesus who he was; and could not for the press, because he was little of stature.', 'καὶ ἐζήτει ἰδεῖν τὸν Ἰησοῦν τίς ἐστιν, καὶ οὐκ ἠδύνατο ἀπὸ τοῦ ὄχλου, ὅτι τῇ ἡλικίᾳ μικρὸς ἦν.', 'kai ezētei idein ton Iēsoun tis estin, kai ouk ēdunato apo tou ochlou, hoti tē hēlikia mikros ēn.', '"He sought to see Jesus who he was" (ezētei idein ton Iēsoun tis estin — he was seeking to see who Jesus is; imperfect: persistent seeking) — the curiosity is genuine and active. "Could not for the press" (ouk ēdunato apo tou ochlou — was not able because of the crowd) — his social marginalization (crowds would not give way for a hated tax collector) and his physical limitation compound. "Little of stature" (tē hēlikia mikros — small in bodily stature) — a charming physical detail unique to Luke, which sets up the sycamore scene. His small stature may also be a narrative metaphor for his social diminishment.', NULL),
  (4, 'And he ran before, and climbed up into a sycomore tree to see him: for he was to pass that way.', 'καὶ προδραμὼν εἰς τὸ ἔμπροσθεν ἀνέβη ἐπὶ συκομορέαν ἵνα ἴδῃ αὐτόν, ὅτι ἐκείνης ἤμελλεν διέρχεσθαι.', 'kai prodramōn eis to emprosthen anebē epi sukomorean hina idē auton, hoti ekeinēs ēmellen dierchesthai.', '"He ran before" (prodramōn — having run ahead, an aorist of quick decisive action) — a wealthy, important official running and climbing a tree is deliberately undignified, echoing the father running to the prodigal son (15:20). "Climbed up into a sycomore tree" (anebē epi sukomorean — went up onto a fig-mulberry tree; the sycamore-fig, common in Jericho, is easy to climb with its low horizontal branches) — the posture is ridiculous by the standards of his social status, which makes the scene both comic and touching. His desperate desire to see Jesus overcomes his dignity.', NULL),
  (5, 'And when Jesus came to the place, he looked up, and saw him, and said unto him, Zacchaeus, make haste, and come down; for to day I must abide at thy house.', 'καὶ ὡς ἦλθεν ἐπὶ τὸν τόπον, ἀναβλέψας ὁ Ἰησοῦς εἶδεν αὐτόν, καὶ εἶπεν πρὸς αὐτόν, Ζακχαῖε, σπεύσας κατάβηθι· σήμερον γὰρ ἐν τῷ οἴκῳ σου δεῖ με μεῖναι.', 'kai hōs ēlthen epi ton topon, anablepsas ho Iēsous eiden auton, kai eipen pros auton, Zakchaie, speusas katabēthi; sēmeron gar en tō oikō sou dei me meinai.', '"Looked up, and saw him" (anablepsas eiden auton) — the same word anablepō used for the blind man receiving sight in 18:42; here Jesus looks up to see the man seeking sight of him. "Zacchaeus" — Jesus addresses him by name without introduction; the divine foreknowledge of names (cf. Simon, 5:8; Saul, Acts 9:4) signals that this encounter was not accidental from Jesus''s side. "I must abide at thy house" (dei me meinai — it is necessary for me to stay; dei = divine necessity) — the same divine compulsion that drove Jesus toward the cross drives him to Zacchaeus''s house. Salvation comes not because Zacchaeus invited Jesus but because Jesus invited himself.', NULL),
  (6, 'And he made haste, and came down, and received him joyfully.', 'καὶ σπεύσας κατέβη, καὶ ὑπεδέξατο αὐτὸν χαίρων.', 'kai speusas katebē, kai hypedexato auton chairōn.', '"Made haste, and came down" (speusas katebē — having hurried he came down) — immediate, unhesitating obedience to Jesus''s command. "Received him joyfully" (hypedexato auton chairōn — welcomed him rejoicing) — the same verb hypodechomai used of Martha in 10:38, of hospitable receiving; here it is full of joy (chairōn — the present participle expresses continuous state of joy). The joy is not manufactured but spontaneous, the natural response to the unexpected grace of being sought and named by Jesus. His response stands in sharp contrast to the rich ruler''s sorrow (18:23).', NULL),
  (7, 'And when they saw it, they all murmured, saying, That he was gone to be guest with a man that is a sinner.', 'καὶ ἰδόντες πάντες διεγόγγυζον λέγοντες ὅτι Παρὰ ἁμαρτωλῷ ἀνδρὶ εἰσῆλθεν καταλῦσαι.', 'kai idontes pantes dieggongyzon legontes hoti Para hamartōlō andri eisēlthen katalusai.', '"They all murmured" (pantes diegonguzon — all were grumbling, the intensified compound verb; the same root as Israel''s wilderness murmuring, Exod 16:7 LXX; found in Luke at 5:30; 15:2) — the crowd''s reaction mirrors the Pharisees'' complaint about Jesus eating with sinners throughout Luke. "A man that is a sinner" (hamartōlō andri — a sinful man) — the word sinner in Luke''s social setting designates not merely a moral failing but a categorical outsider. The murmuring crowd does not understand that Jesus''s presence with sinners is not contamination but invasion — the kingdom entering enemy territory.', NULL),
  (8, 'And Zacchaeus stood, and said unto the Lord; Behold, Lord, the half of my goods I give to the poor; and if I have taken any thing from any man by false accusation, I restore him fourfold.', 'σταθεὶς δὲ Ζακχαῖος εἶπεν πρὸς τὸν Κύριον, Ἰδοὺ τὰ ἡμίσιά μου τῶν ὑπαρχόντων, Κύριε, τοῖς πτωχοῖς δίδωμι, καὶ εἴ τινός τι ἐσυκοφάντησα, ἀποδίδωμι τετραπλοῦν.', 'statheis de Zakchaios eipen pros ton Kurion, Idou ta hēmisia mou tōn huparchontōn, Kurie, tois ptōchois didōmi, kai ei tinos ti esukophantēsa, apodidōmi tetraploun.', '"Stood" (statheis — having stood, taking a public formal position) — the act of standing to speak indicates a solemn public declaration. "The half of my goods I give to the poor" (ta hēmisia mou tōn huparchontōn...didōmi — the half of my possessions I give; present tense: I am now giving, an immediate commitment) — voluntarily giving half, without being asked. "If I have taken any thing from any man by false accusation" (ei tinos ti esukophantēsa — if I have extorted anything from anyone; sukophantēō is the word for extortion, blackmail, false accusation) "I restore him fourfold" (apodidōmi tetraploun) — exceeding Mosaic law''s requirement (Exod 22:1 required fourfold restitution only for stolen sheep). Salvation has immediately restructured his economics.', NULL),
  (9, 'And Jesus said unto him, This day is salvation come to this house, forsomuch as he also is a son of Abraham.', 'εἶπεν δὲ πρὸς αὐτὸν ὁ Ἰησοῦς, Σήμερον σωτηρία τῷ οἴκῳ τούτῳ ἐγένετο, καθότι καὶ αὐτὸς υἱὸς Ἀβραάμ ἐστιν·', 'eipen de pros auton ho Iēsous, Sēmeron sōtēria tō oikō toutō egeneto, kathoti kai autos huios Abraam estin;', '"This day is salvation come to this house" (Sēmeron sōtēria tō oikō toutō egeneto — today salvation to this house has happened) — salvation is dated ("today," sēmeron, a key word in Luke: 2:11; 4:21; 23:43), located ("to this house"), and declared (egeneto — aorist: it happened, it has arrived). "He also is a son of Abraham" (autos huios Abraam estin — he himself is a son of Abraham) — not merely by ethnic lineage but by faith like Abraham''s (Gal 3:7; Rom 4:11-12). The crowd had categorized him as a sinner; Jesus recategorizes him as a son of Abraham. His restitution is not the cause of salvation but its fruit and evidence.', NULL),
  (10, 'For the Son of man is come to seek and to save that which was lost.', 'ἦλθεν γὰρ ὁ Υἱὸς τοῦ ἀνθρώπου ζητῆσαι καὶ σῶσαι τὸ ἀπολωλός.', 'ēlthen gar ho Huios tou anthrōpou zētēsai kai sōsai to apolōlos.', '"The Son of man is come to seek and to save that which was lost" (ēlthen...zētēsai kai sōsai to apolōlos — came...to seek and to save the one having been lost) — a programmatic mission statement, echoing 15:3-7 (the lost sheep). "To seek" (zētēsai) and "to save" (sōsai) are infinitives of purpose: this is why he came. "That which was lost" (to apolōlos — the perfect passive participle: the one in a state of lostness, the permanently lost one) — the same verb used throughout chapter 15. The Zacchaeus episode is the final concrete illustration of the lost-and-found theology of chapters 15-19 before the passion narrative begins.', NULL),
  (11, 'And as they heard these things, he added and spake a parable, because he was nigh to Jerusalem, and because they thought that the kingdom of God should immediately appear.', 'Ἀκουόντων δὲ αὐτῶν ταῦτα, προσθεὶς εἶπεν παραβολήν, διὰ τὸ ἐγγὺς αὐτὸν εἶναι Ἰερουσαλὴμ καὶ δοκεῖν αὐτοὺς ὅτι παραχρῆμα μέλλει ἡ βασιλεία τοῦ Θεοῦ ἀναφαίνεσθαι.', 'Akouontōn de autōn tauta, prostheis eipen parabolēn, dia to engus auton einai Ierousalēm kai dokein autous hoti parachrēma mellei hē basileia tou Theou anaphainesthai.', 'Luke explicitly states the occasion and purpose of the parable: proximity to Jerusalem has inflamed the disciples'' expectation that the kingdom of God would "immediately appear" (parachrēma — instantly, at once; anaphainesthai — be manifested, become visible). The misconception is that the Messiah''s arrival in Jerusalem will trigger the kingdom''s immediate visible establishment, overthrowing Rome and restoring Israel''s national sovereignty. The parable will correct this timeline: the king departs, entrusts resources, and returns later for accountability. The interval between departure and return is the present age.', NULL),
  (12, 'He said therefore, A certain nobleman went into a far country to receive for himself a kingdom, and to return.', 'εἶπεν οὖν, Ἄνθρωπός τις εὐγενὴς ἐπορεύθη εἰς χώραν μακράν, λαβεῖν ἑαυτῷ βασιλείαν καὶ ὑποστρέψαι.', 'eipen oun, Anthrōpos tis eugenēs eporeuthē eis chōran makran, labein heautō basileian kai hupostrepsai.', '"A certain nobleman" (Anthrōpos tis eugenēs — a certain noble-born man, a man of high birth) "went into a far country" (eporeuthē eis chōran makran — traveled to a distant land) "to receive for himself a kingdom" (labein heautō basileian — to receive for himself a kingdom, to obtain royal authority). The political framework almost certainly alludes to Archelaus''s journey to Rome in 4 BC to have his rule confirmed — an event well-known to Jesus''s Jewish listeners. The "far country" thus represents the heavenly realm to which Christ ascends; the interval represents the present age; the return is the parousia.', NULL),
  (13, 'And he called his ten servants, and delivered them ten pounds, and said unto them, Occupy till I come.', 'καλέσας δὲ δέκα δούλους ἑαυτοῦ ἔδωκεν αὐτοῖς δέκα μνᾶς καὶ εἶπεν πρὸς αὐτούς, Πραγματεύσασθε ἐν ᾧ ἔρχομαι.', 'kalEsas de deka doulous heautou edōken autois deka mnas kai eipen pros autous, Pragmateusasthe en hō erchomai.', '"Ten servants" (deka doulous) — one mina each; contrast Matthew''s parable of the talents where each servant receives different amounts. "Ten pounds" (deka mnas — ten minas; one mina = approximately 100 denarii, about three months'' wages for a laborer) — a modest sum, unlike Matthew''s talents (one talent = 6,000 denarii). "Occupy till I come" (Pragmateusasthe en hō erchomai — do business, trade actively while I am coming) — the present tense erchomai (I am coming) emphasizes the ongoing nature of the master''s approach; the servant''s trading activity is the appropriate response to the master''s continuing claim on them.', NULL),
  (14, 'But his citizens hated him, and sent a message after him, saying, We will not have this man to reign over us.', 'οἱ δὲ πολῖται αὐτοῦ ἐμίσουν αὐτόν, καὶ ἀπέστειλαν πρεσβείαν ὀπίσω αὐτοῦ λέγοντες, Οὐ θέλομεν τοῦτον βασιλεῦσαι ἐφ'' ἡμᾶς.', 'hoi de politai autou emisoun auton, kai apesteilan presbeian opisō autou legontes, Ou thelomen touton basilEusai eph'' hēmas.', '"His citizens hated him" (hoi politai autou emisoun auton — the citizens of his city hated him, imperfect: a settled state of hatred) — the political framework introduces a third category beyond the servants: citizens who reject the nobleman''s right to rule. "Sent a message after him" (apesteilan presbeian — dispatched an embassy, a formal diplomatic delegation) — a coordinated act of political rejection. "We will not have this man to reign over us" (Ou thelomen touton basileusai eph'' hēmas — we do not wish this one to reign over us) — the refusal of Christ''s kingship by those who heard and rejected his message.', NULL),
  (15, 'And it came to pass, that when he was returned, having received the kingdom, then he commanded these servants to be called unto him, to whom he had given the money, that he might know how much every man had gained by trading.', 'Καὶ ἐγένετο ἐν τῷ ἐπανελθεῖν αὐτὸν λαβόντα τὴν βασιλείαν, καὶ εἶπεν φωνηθῆναι αὐτῷ τοὺς δούλους τούτους οἷς ἔδωκεν τὸ ἀργύριον, ἵνα γνῷ τί διεπραγματεύσαντο.', 'Kai egeneto en tō epanelthein auton labonta tēn basileian, kai eipen phōnēthēnai autō tous doulous toutous hois edōken to argurion, hina gnō ti diepragmateusanto.', '"When he was returned, having received the kingdom" (epanelthein auton labonta tēn basileian — when he came back having received the kingdom) — the return is certain and the kingdom is already obtained when he returns. "That he might know how much every man had gained by trading" (hina gnō ti diepragmateusanto — in order that he might know what they had transacted, what they had earned through business) — the master conducts an accounting review, not a punishment session; the review is diagnostic, revealing the character of each servant''s stewardship.', NULL),
  (16, 'Then came the first, saying, Lord, thy pound hath gained ten pounds.', 'παρεγένετο δὲ ὁ πρῶτος λέγων, Κύριε, ἡ μνᾶ σου δέκα μνᾶς προσηργάσατο.', 'paregeneto de ho prōtos legōn, Kurie, hē mna sou deka mnas prosērgasato.', '"Thy pound hath gained ten pounds" (hē mna sou deka mnas prosērgasato — your mina has earned in addition ten minas; prosērgasato — earned additionally, a profit verb) — a 1,000% return. The servant attributes the gain to the master''s mina ("thy pound") rather than to his own skill — an important theological signal: the servant is a steward, not an owner. The ten minas are not the servant''s to boast about but the master''s to receive. This posture of stewardship (not ownership) characterizes the faithful servant.', NULL),
  (17, 'And he said unto him, Well, thou good servant: because thou hast been faithful in a very little, have thou authority over ten cities.', 'καὶ εἶπεν αὐτῷ, Εὖγε, ἀγαθὲ δοῦλε· ὅτι ἐν ἐλαχίστῳ πιστὸς ἐγένου, ἴσθι ἐξουσίαν ἔχων ἐπάνω δέκα πόλεων.', 'kai eipen autō, Euge, agathe doule; hoti en elachistō pistos egenou, isthi exousian echōn epanō deka poleōn.', '"Well" (Euge — Bravo! Well done! an exclamation of enthusiastic approval, used only here in the NT) — the master''s delight is genuine and enthusiastic. "Faithful in a very little" (en elachistō pistos — faithful in the smallest thing; elachiston = superlative of small) — the mina is characterized as very small in comparison to the reward, establishing the principle of 16:10: "he that is faithful in that which is least is faithful also in much." "Authority over ten cities" — the reward for faithfulness is expanded governance, not retirement. Kingdom faithfulness leads to kingdom service at greater scale.', NULL),
  (18, 'And the second came, saying, Lord, thy pound hath gained five pounds.', 'καὶ ἦλθεν ὁ δεύτερος λέγων, Κύριε, ἡ μνᾶ σου ἐποίησεν πέντε μνᾶς.', 'kai ēlthen ho deuteros legōn, Kurie, hē mna sou epoiēsen pente mnas.', '"Thy pound hath gained five pounds" (hē mna sou epoiEsen pente mnas — your mina produced five minas) — a 500% return, less than the first servant but still significant. Notably the master''s commendation (v.19) mirrors v.17 except for the number of cities — "five cities" rather than "ten." The principle is consistent: faithful stewardship, proportionate reward. The parable does not grade the servants against each other but evaluates each in relation to what was entrusted and what was done with it.', NULL),
  (19, 'And he said likewise to him, Be thou also over five cities.', 'εἶπεν δὲ καὶ τούτῳ, Καὶ σὺ ἐπάνω γίνου πέντε πόλεων.', 'eipen de kai toutō, Kai su epanō ginou pente poleōn.', '"Be thou also over five cities" (Kai su epanō ginou pente poleōn — you also become over five cities; the imperative ginou — become, as a standing command) — the reward structure is symmetrical with the service: five minas earned, five cities governed. The "also" (kai su — you also) places this servant alongside the first in the category of the faithful; there is no rebuke, no graduated evaluation suggesting he is less valued than the first servant. Both faithful servants receive the kingdom''s governance in proportion to their stewardship.', NULL),
  (20, 'And another came, saying, Lord, behold, here is thy pound, which I have kept laid up in a napkin:', 'καὶ ὁ ἕτερος ἦλθεν λέγων, Κύριε, ἰδοὺ ἡ μνᾶ σου, ἣν εἶχον ἀποκειμένην ἐν σουδαρίῳ·', 'kai ho heteros ēlthen legōn, Kurie, idou hē mna sou, hēn eichon apokeimEnēn en soudariō;', '"Here is thy pound, which I have kept laid up in a napkin" (ēn eichon apokeimEnēn en soudariō — which I had stored away in a cloth; soudariō — the same word for the cloth over Lazarus''s face in John 11:44) — not buried (as in Matthew''s parable) but wrapped and stored. The napkin suggests careful preservation rather than negligent disregard, but the result is the same: no investment, no growth, no risk. The servant will claim his motive was fear (v.21). Preservation of the entrusted gift without deployment is unfaithfulness regardless of the motive.', NULL),
  (21, 'For I feared thee, because thou art an austere man: thou takest up that thou layedst not down, and reapest that thou didst not sow.', 'ἐφοβούμην γάρ σε, ὅτι ἄνθρωπος αὐστηρὸς εἶ, αἴρεις ὃ οὐκ ἔθηκας, καὶ θερίζεις ὃ οὐκ ἔσπειρας.', 'ephoboumēn gar se, hoti anthrōpos austēros ei, aireis ho ouk ethēkas, kai therizeis ho ouk espeiras.', '"I feared thee" (ephoboumEn — I was fearing you, an imperfect of continuous fear) "because thou art an austere man" (austēros — harsh, strict, exacting; from austēros, related to the word for dried-out, astringent, harsh to the taste) — the characterization of the master as harsh is the servant''s self-justification, not an accurate description of the master who celebrated the faithful servants with delight (Euge, v.17). The servant projects severity onto the master as a rationalization for his own paralysis. "Thou takest up that thou layedst not down" — the servant claims the master''s demands are unreasonable, but this description is precisely what the first servant demonstrated could be met.', NULL),
  (22, 'And he saith unto him, Out of thine own mouth will I judge thee, thou wicked servant. Thou knewest that I was an austere man, taking up that I laid not down, and reaping that I did not sow:', 'λέγει αὐτῷ, Ἐκ τοῦ στόματός σου κρινῶ σε, πονηρὲ δοῦλε. ᾔδεις ὅτι ἐγὼ ἄνθρωπος αὐστηρός εἰμι, αἴρων ὃ οὐκ ἔθηκα καὶ θερίζων ὃ οὐκ ἔσπειρα·', 'legei autō, Ek tou stomatos sou krinō se, ponēre doule. ēdeis hoti egō anthrōpos austēros eimi, airōn ho ouk ethēka kai therizōn ho ouk espeira;', '"Out of thine own mouth will I judge thee" (Ek tou stomatos sou krinō se — from your own mouth I will judge you) — the servant''s self-incrimination: if he genuinely believed the master was demanding, the logical response would have been maximum effort, not minimum effort. "Thou wicked servant" (ponēre doule — evil servant, the opposite of the "good servant" in v.17) — the judgment is not because he failed to achieve but because his inaction revealed his character. "Thou knewest" (ēdeis — you knew, you had knowledge) — the judgment rests on the servant''s own stated awareness of the master''s expectations.', NULL),
  (23, 'Wherefore then gavest not thou my money into the bank, that at my coming I might have required mine own with usury?', 'καὶ διὰ τί οὐκ ἔδωκάς μου τὸ ἀργύριον ἐπὶ τράπεζαν, κἀγὼ ἐλθὼν σὺν τόκῳ ἂν αὐτὸ ἔπραξα;', 'kai dia ti ouk edōkas mou to argurion epi trapezan, kagō elthōn sun tokō an auto epraza?', '"Gavest not thou my money into the bank" (epi trapezan — upon the table, the money-changers'' table; trapeza = table, then bank) "that at my coming I might have required mine own with usury?" (sun tokō — with interest, with offspring; tokos = birth, interest as the offspring of capital) — the absolute minimum expectation was banking the mina for interest, which required no personal risk. The servant chose instead the option of zero risk, zero gain, and zero service. The master''s question exposes that even by the servant''s own stated logic, passive banking would have been better than wrapping in a napkin.', NULL),
  (24, 'And he said unto them that stood by, Take from him the pound, and give it to him that hath ten pounds.', 'καὶ τοῖς παρεστῶσιν εἶπεν, Ἄρατε ἀπ'' αὐτοῦ τὴν μνᾶν καὶ δότε τῷ τὰς δέκα μνᾶς ἔχοντι.', 'kai tois parestōsin eipen, Arate ap'' autou tēn mnan kai dote tō tas deka mnas echonti.', '"Take from him the pound" (Arate ap'' autou tēn mnan — take away from him the mina) — the unfaithful servant loses not only his future opportunity but his present entrustment. "Give it to him that hath ten pounds" — the gift is given to the most productive servant, not distributed equally. The economy of the kingdom is not redistributive equality but reward proportional to faithfulness. This principle will be stated explicitly in v.26.', NULL),
  (25, '(And they said unto him, Lord, he hath ten pounds.)', '(καὶ εἶπαν αὐτῷ, Κύριε, ἔχει δέκα μνᾶς.)', '(kai eipan autō, Kurie, echei deka mnas.)', 'A brief interjection from bystanders, perhaps expressing surprise at the distribution: why give more to the one who already has the most? The parenthetical objection (unique to Luke''s version) serves to set up the master''s clarifying principle in v.26. The bystanders'' logic is egalitarian: it seems unfair to give the already-enriched servant even more. Jesus''s response will challenge this instinct with a different economy.', NULL),
  (26, 'For I say unto you, That unto every one which hath shall be given; and from him that hath not, even that he hath shall be taken away from him.', 'λέγω γὰρ ὑμῖν ὅτι παντὶ τῷ ἔχοντι δοθήσεται, ἀπὸ δὲ τοῦ μὴ ἔχοντος καὶ ὃ ἔχει ἀρθήσεται.', 'legō gar humin hoti panti tō echonti dothēsetai, apo de tou mē echontos kai ho echei arthēsetai.', '"Unto every one which hath shall be given" (panti tō echonti dothēsetai — to everyone who has it will be given) — the kingdom''s economy: faithful use of what is entrusted creates capacity for more; the active steward''s resources multiply. "From him that hath not, even that he hath shall be taken away" (apo de tou mē echontos kai ho echei arthēsetai — from the one not having, even what he has will be taken) — the inactive steward, by refusing to deploy his resources, has already forfeited his stewardship in principle; the formal stripping merely makes visible what was already spiritually true. This principle appears also in 8:18 and Matthew 25:29.', NULL),
  (27, 'But those mine enemies, which would not that I should reign over them, bring hither, and slay them before me.', 'πλὴν τοὺς ἐχθρούς μου τούτους τοὺς μὴ θελήσαντάς με βασιλεῦσαι ἐπ'' αὐτούς, ἀγάγετε ὧδε καὶ κατασφάξατε αὐτοὺς ἔμπροσθέν μου.', 'plēn tous echthrous mou toutous tous mē thelEsantas me basilEusai ep'' autous, agagete hōde kai katasphaxate autous emprosthen mou.', '"Those mine enemies, which would not that I should reign over them" (tous mē thelēsantas me basileusai ep'' autous — those not having wished me to reign over them) — the third category: not negligent servants but active rejecters of the king''s sovereignty, the embassy-senders of v.14. "Bring hither, and slay them before me" (agagete hōde kai katasphaxate — lead here and slaughter; katasphazō is a strong word for killing in battle) — the harsh conclusion of the political allegory. In historical terms, this was literally fulfilled in the Roman destruction of Jerusalem in AD 70.', NULL),
  (28, 'And when he had thus spoken, he went before, ascending up to Jerusalem.', 'Καὶ εἰπὼν ταῦτα ἐπορεύετο ἔμπροσθεν, ἀναβαίνων εἰς Ἱεροσόλυμα.', 'Kai eipōn tauta eporeueto emprosthen, anabainōn eis Hierosoluma.', '"He went before, ascending up to Jerusalem" (eporeueto emprosthen, anabainōn eis Hierosoluma — he was going ahead, going up to Jerusalem) — the journey to Jerusalem, announced in 9:51, is now reaching its climax. "Went before" (emprosthen — in front, leading the way) — Jesus leads the way into what he has just described in prophetic parable. The ascent to Jerusalem (anabainōn — going up, as the city was on a hill, always "going up" in Jewish usage) is both physical and typological: the king approaches his capital and his cross.', NULL),
  (29, 'And it came to pass, when he was come nigh to Bethphage and Bethany, at the mount called the mount of Olives, he sent two of his disciples,', 'Καὶ ἐγένετο ὡς ἤγγισεν εἰς Βηθφαγὴ καὶ Βηθανίαν πρὸς τὸ ὄρος τὸ καλούμενον Ἐλαιών, ἀπέστειλεν δύο τῶν μαθητῶν', 'Kai egeneto hōs ēngisen eis Bēthphagē kai Bēthanian pros to oros to kaloumenon Elaiōn, apesteilen duo tōn mathētōn', '"Bethphage and Bethany" — two villages on the southeastern slope of the Mount of Olives, approximately two miles from Jerusalem. "The mount called the mount of Olives" (Elaiōn — the Olive Garden/Mount; from elaia, olive) — the eastern approach to Jerusalem, associated with Zechariah''s eschatological prophecy (Zech 14:4: "his feet shall stand in that day upon the mount of Olives") and with David''s flight from Absalom (2 Sam 15:30). The geography is deliberately Davidic and eschatological.', NULL),
  (30, 'Saying, Go ye into the village over against you; in the which at your entering ye shall find a colt tied, whereon yet never man sat: loose him, and bring him hither.', 'λέγων, Ὑπάγετε εἰς τὴν κατέναντι κώμην, ἐν ᾗ εἰσπορευόμενοι εὑρήσετε πῶλον δεδεμένον, ἐφ'' ὃν οὐδεὶς πώποτε ἀνθρώπων ἐκάθισεν, καὶ λύσαντες αὐτὸν ἀγάγετε.', 'legōn, Hupagete eis tēn katenanti kōmēn, en hē eisporeuomenoi heurēsete pōlon dedemenon, eph'' hon oudeis pōpote anthrōpōn ekathisen, kai lusantes auton agagete.', '"A colt tied, whereon yet never man sat" (pōlon dedemenon, eph'' hon oudeis pōpote anthrōpōn ekathisen — a colt having been tied, on which no one ever of men sat) — the unridden colt is ritually significant: an animal not yet used for work was considered appropriate for sacred purposes (Num 19:2; Deut 21:3; 1 Sam 6:7). The detail fulfills Zechariah 9:9: "thy King cometh unto thee...riding upon a colt the foal of an ass." The prearranged plan (Jesus knew the colt would be there) suggests prior arrangements, or alternatively demonstrates prophetic foreknowledge.', NULL),
  (31, 'And if any man ask you, Why do ye loose him? thus shall ye say unto him, Because the Lord hath need of him.', 'καὶ ἐάν τις ὑμᾶς ἐρωτᾷ, Διατί λύετε; οὕτως ἐρεῖτε αὐτῷ ὅτι Ὁ Κύριος αὐτοῦ χρείαν ἔχει.', 'kai ean tis humas erōtā, Diatī luete? houtōs ereite autō hoti Ho Kurios autou chreian echei.', '"The Lord hath need of him" (Ho Kurios autou chreian echei — the Lord of it has need) — the title "Lord" (Kurios) applied to Jesus here carries its full weight: the Lord of all things claims what is his own. "Hath need of" (chreian echei — has a need of, has a use for) — the King commandeers what he needs. The combination of sovereignty and need is characteristic of the Incarnation: the one who owns all things nonetheless operates within the conditions of genuine human need and historical contingency.', NULL),
  (32, 'And they that were sent went their way, and found even as he had said unto them.', 'ἀπελθόντες δὲ οἱ ἀπεσταλμένοι εὗρον καθὼς εἶπεν αὐτοῖς.', 'apelthontes de hoi apestalmenoi heuron kathōs eipen autois.', '"Found even as he had said unto them" (heuron kathōs eipen autois — they found exactly as he had said) — the precise fulfillment of Jesus''s word. The disciples find exactly what they were told they would find, exactly where they were told to look. The detail is a quiet confirmation of Jesus''s prophetic foreknowledge and demonstrates that the entry into Jerusalem is a deliberate, orchestrated act, not an improvised popular reaction.', NULL),
  (33, 'And as they were loosing the colt, the owners thereof said unto them, Why loose ye the colt?', 'λυόντων δὲ αὐτῶν τὸν πῶλον, εἶπαν οἱ κύριοι αὐτοῦ πρὸς αὐτούς, Τί λύετε τὸν πῶλον;', 'luontōn de autōn ton pōlon, eipan hoi kurioi autou pros autous, Ti luete ton pōlon?', '"The owners thereof" (hoi kurioi autou — the lords/owners of it; kurios can mean both Lord and owner) — a wordplay may be present: the owners (kurioi) of the colt ask why it is being taken; the answer will be "the Lord" (ho Kurios, v.34) needs it. The human owners do not initially recognize that the Lord of the colt transcends their ownership of it. The owners'' question is natural and legitimate; the disciples have the ready answer prepared.', NULL),
  (34, 'And they said, The Lord hath need of him.', 'οἱ δὲ εἶπαν ὅτι Ὁ Κύριος αὐτοῦ χρείαν ἔχει.', 'hoi de eipan hoti Ho Kurios autou chreian echei.', 'The disciples repeat Jesus''s exact words verbatim: "The Lord hath need of him" — the phrase functions as both an explanation and a claim of sovereignty. In the wider Lucan context, the "Lord" is always Jesus (cf. 1:43, 45; 2:11); the claim that "the Lord needs it" is a statement about who Jesus is, not merely an explanation of borrowing. The owners'' apparent willingness to release the colt on this basis suggests either prior arrangement or a divinely ordered willingness — both are consistent with Luke''s theology.', NULL),
  (35, 'And they brought him to Jesus: and they cast their garments upon the colt, and they set Jesus thereon.', 'καὶ ἤγαγον αὐτὸν πρὸς τὸν Ἰησοῦν· καὶ ἐπιρίψαντες αὐτῶν τὰ ἱμάτια ἐπὶ τὸν πῶλον ἐπεβίβασαν τὸν Ἰησοῦν.', 'kai ēgagon auton pros ton Iēsoun; kai epiripsantes autōn ta himatia epi ton pōlon epebibasan ton Iēsoun.', '"Cast their garments upon the colt" (epiripsantes ta himatia epi ton pōlon — having thrown their garments onto the colt) — the placing of garments on the riding animal is an honor gesture, reflecting the royal inauguration of Jehu in 2 Kings 9:13 where the people spread their garments beneath him on the steps. The disciples'' action thus carries royal inauguration overtones. "They set Jesus thereon" (epebibasan ton Iēsoun — they mounted Jesus onto it) — a note of the disciples'' active participation in the royal proclamation.', NULL),
  (36, 'And as he went, they spread their clothes in the way.', 'πορευομένου δὲ αὐτοῦ, ὑπεστρώννυον τὰ ἱμάτια αὐτῶν ἐν τῇ ὁδῷ.', 'poreuomenou de autou, hupestōnnuon ta himatia autōn en tē hodō.', '"They spread their clothes in the way" (hupestōnnuon ta himatia autōn en tē hodō — they were spreading their garments in the road; the imperfect continuous: a continuing action as the procession moved forward) — the carpet of garments is a royal honor gesture, again echoing 2 Kings 9:13 and the entry of a king. The road from the Mount of Olives to Jerusalem descends into the Kidron Valley and then ascends sharply to the city gates — a dramatic visual spectacle, visible to the whole city.', NULL),
  (37, 'And when he was come nigh, even now at the descent of the mount of Olives, the whole multitude of the disciples began to rejoice and praise God with a loud voice for all the mighty works that they had seen;', 'Ἐγγίζοντος δὲ αὐτοῦ ἤδη πρὸς τῇ καταβάσει τοῦ ὄρους τῶν Ἐλαιῶν, ἤρξαντο ἅπαν τὸ πλῆθος τῶν μαθητῶν χαίροντες αἰνεῖν τὸν Θεὸν φωνῇ μεγάλῃ περὶ πασῶν ὧν εἶδον δυνάμεων,', 'Engizōn de autou ēdē pros tē katabAsei tou orous tōn Elaiōn, ērxanto hapan to plēthos tōn mathētōn chairontes ainein ton Theon phōnē megalē peri pasōn hōn eidon dunameōn,', '"At the descent of the mount of Olives" — the moment the city comes into view from the downward slope is the moment the disciples'' praise erupts. "The whole multitude of the disciples" (hapan to plēthos tōn mathētōn — all the mass of the disciples) — not just the Twelve but the larger circle of followers who had accompanied the journey. "Rejoice and praise God with a loud voice" (chairontes ainein ton Theon phōnē megalē — rejoicing, praising God with a great voice) "for all the mighty works that they had seen" (peri pasōn hōn eidon dunameōn — concerning all the works of power they had seen) — the praise is grounded in witnessed evidence.', NULL),
  (38, 'Saying, Blessed be the King that cometh in the name of the Lord: peace in heaven, and glory in the highest.', 'λέγοντες, Εὐλογημένος ὁ ἐρχόμενος Βασιλεὺς ἐν ὀνόματι Κυρίου· εἰρήνη ἐν οὐρανῷ καὶ δόξα ἐν ὑψίστοις.', 'legontes, Eulogēmenos ho erchomenos Basileus en onomati Kuriou; eirēnē en ouranō kai doxa en hupsistois.', '"Blessed be the King that cometh in the name of the Lord" — a quotation of Psalm 118:26 (used at Tabernacles and Passover, a royal messianic psalm) with the insertion of "the King" (Basileus) — Luke''s version explicitly identifies the incoming one as King. "Peace in heaven, and glory in the highest" — Luke''s version differs from Mark and Matthew''s "Hosanna in the highest": where the infancy narrative announced "peace on earth" (2:14), the entry hymn announces "peace in heaven" — the reconciliation of heaven and earth accomplished through the King''s coming.', NULL),
  (39, 'And some of the Pharisees from among the multitude said unto him, Master, rebuke thy disciples.', 'καί τινες τῶν Φαρισαίων ἀπὸ τοῦ ὄχλου εἶπαν πρὸς αὐτόν, Διδάσκαλε, ἐπιτίμησον τοῖς μαθηταῖς σου.', 'kai tines tōn Pharisaiōn apo tou ochlou eipan pros auton, Didaskale, epitimēson tois mathētais sou.', '"Rebuke thy disciples" (epitimēson tois mathētais sou — reprimand your disciples) — the Pharisees address Jesus respectfully as "Teacher" (Didaskale) but demand he suppress the messianic proclamation. Their concern may be both theological (objection to the royal messianic claim) and political (fear of Roman response to royal demonstrations). "Rebuke" (epitimēson) — the same word used of rebuking demons; the Pharisees want Jesus to silence what they perceive as a dangerous and unauthorized proclamation.', NULL),
  (40, 'And he answered and said unto them, I tell you that, if these should hold their peace, the stones would immediately cry out.', 'καὶ ἀποκριθεὶς εἶπεν, Λέγω ὑμῖν ὅτι ἐὰν οὗτοι σιωπήσωσιν, οἱ λίθοι κράξουσιν.', 'kai apokritheis eipen, Legō humin hoti ean houtoi siōpēsōsin, hoi lithoi kraxousin.', '"The stones would immediately cry out" (hoi lithoi kraxousin — the stones will cry out, shout aloud; a future of certainty) — a hyperbolic declaration of inevitability: the entry of the King into his city is so cosmically significant that even inanimate matter would give testimony if the disciples were silenced. The saying may allude to Habakkuk 2:11 ("the stone shall cry out of the wall"). This is not a general principle about nature''s praise but a specific statement: this moment — the Messiah''s entry — is so significant that nothing can suppress its proclamation.', NULL),
  (41, 'And when he was come near, he beheld the city, and wept over it,', 'Καὶ ὡς ἤγγισεν, ἰδὼν τὴν πόλιν ἔκλαυσεν ἐπ'' αὐτήν,', 'Kai hōs ēngisen, idōn tēn polin eklausen ep'' autēn,', '"He beheld the city, and wept over it" (idōn tēn polin eklausen ep'' autēn — having seen the city he wept over it) — this is one of only three recorded instances of Jesus weeping in the Gospels (also John 11:35 and possibly John 12:27). "Wept" (eklausen — imperfect in the best manuscripts: he was weeping, he kept weeping) — not a single tear but sustained grief. The triumphal entry suddenly, shockingly, becomes a weeping entry. The crowd praises; Jesus weeps. The contrast is devastating: they celebrate a political triumph; he mourns an impending catastrophe they cannot see.', NULL),
  (42, 'Saying, If thou hadst known, even thou, at least in this thy day, the things which belong unto thy peace! but now they are hid from thine eyes.', 'λέγων ὅτι Εἰ ἔγνως καὶ σύ, καὶ γε ἐν τῇ ἡμέρᾳ σου ταύτῃ, τὰ πρὸς εἰρήνην σου· νῦν δὲ ἐκρύβη ἀπὸ ὀφθαλμῶν σου.', 'legōn hoti Ei egnōs kai su, kai ge en tē hēmera sou tautē, ta pros eirēnēn sou; nun de ekrubē apo ophthalmōn sou.', '"If thou hadst known" (Ei egnōs — if you had known, an unfulfilled condition) "the things which belong unto thy peace" (ta pros eirēnēn sou — the things toward your peace, what makes for your peace) — the city whose name includes "peace" (Yeru-shalom) does not recognize the Prince of Peace in its midst. "In this thy day" (en tē hēmera sou tautē — in this your day) — the day of visitation, the day of opportunity. "Now they are hid from thine eyes" (nun de ekrubē apo ophthalmōn sou — but now it has been hidden from your eyes, a divine passive) — the hiding, as in 18:34, is both judicial and tragic: Jerusalem has chosen blindness and blindness has been confirmed.', NULL),
  (43, 'For the days shall come upon thee, that thine enemies shall cast a trench about thee, and compass thee round, and keep thee in on every side,', 'ὅτι ἥξουσιν ἡμέραι ἐπὶ σέ, καὶ παρεμβαλοῦσιν οἱ ἐχθροί σου χάρακά σοι καὶ περικυκλώσουσίν σε καὶ συνέξουσίν σε πάντοθεν,', 'hoti hēxousin hēmerai epi se, kai parembaloуsin hoi echthroi sou charaka soi kai perikuklōsousin se kai sunexousin se pantothen,', '"The days shall come upon thee" (hēxousin hēmerai epi se — days will come upon you) — prophetic language typical of OT judgment oracles. "Cast a trench about thee" (charakā soi — a palisade, a siege wall; charax = sharpened stake, military palisade) — a technical description of Roman siege warfare, literally fulfilled in the Roman siege of Jerusalem under Titus (AD 66-70) who built a wall around the city. "Compass thee round, and keep thee in on every side" (perikuklōsousin kai sunexousin se pantothen — surround and hem in from all sides) — the encirclement that preceded the Roman assault.', NULL),
  (44, 'And shall lay thee even with the ground, and thy children within thee; and they shall not leave in thee one stone upon another; because thou knewest not the time of thy visitation.', 'καὶ ἐδαφιοῦσίν σε καὶ τὰ τέκνα σου ἐν σοί, καὶ οὐκ ἀφήσουσιν ἐν σοὶ λίθον ἐπὶ λίθῳ, ἀνθ'' ὧν οὐκ ἔγνως τὸν καιρὸν τῆς ἐπισκοπῆς σου.', 'kai edaphiousin se kai ta tekna sou en soi, kai ouk aphēsousin en soi lithon epi lithō, anth'' hōn ouk egnōs ton kairon tēs episkopēs sou.', '"Lay thee even with the ground" (edaphiousin se — will dash you to the ground, raze you; edaphos = floor, ground) "thy children within thee" — a devastating picture of slaughter during the siege. "Not leave in thee one stone upon another" (ouk aphēsousin lithon epi lithō — will not leave stone upon stone) — fulfilled in the Roman destruction of 70 AD when Titus demolished the Temple and much of the city. "Because thou knewest not the time of thy visitation" (ton kairon tēs episkopēs sou — the season of your visitation/inspection; episkopē = visitation, pastoral oversight, inspection by a superior) — the root cause of the catastrophe: failure to recognize the Messiah''s arrival.', NULL),
  (45, 'And he went into the temple, and began to cast out them that sold therein, and them that bought;', 'Καὶ εἰσελθὼν εἰς τὸ ἱερὸν ἤρξατο ἐκβάλλειν τοὺς πωλοῦντας ἐν αὐτῷ καὶ τοὺς ἀγοράζοντας,', 'Kai eiselthōn eis to hieron ērxato ekballein tous pōlountas en autō kai tous agorazontas,', '"Went into the temple" (eiselthōn eis to hieron — having entered into the temple complex; hieron = the whole Temple precincts, including the Court of the Gentiles where the commercial activity occurred) — the Temple action immediately follows the entry. "Cast out them that sold therein, and them that bought" (ekballein tous pōlountas kai tous agorazontas — to throw out those selling and those buying) — Luke''s account is the most compressed of the Synoptics, without the detail of overturned tables (Mark 11:15-16). The commercial exchange itself is the problem: the Temple had become a market.', NULL),
  (46, 'Saying unto them, It is written, My house is the house of prayer: but ye have made it a den of thieves.', 'λέγων αὐτοῖς, Γέγραπται, Ὁ οἶκός μου οἶκος προσευχῆς ἐσται· ὑμεῖς δὲ αὐτὸν ἐποιήσατε σπήλαιον λῃστῶν.', 'legōn autois, Gegraptai, Ho oikos mou oikos proseuchēs estai; humeis de auton epoiēsate spēlaion lēstōn.', '"It is written" (Gegraptai — the perfect passive of graphō, the standard formula for citing authoritative Scripture) — two texts are combined: "My house is the house of prayer" from Isaiah 56:7 (where the full text includes "for all nations," which Mark preserves but Luke omits — significant in light of Luke''s universal emphasis elsewhere) and "a den of thieves" (spēlaion lēstōn) from Jeremiah 7:11. Jeremiah''s "den of robbers" occurs in a Temple sermon about the false security of Temple attendance combined with injustice. The combination of Isaiah and Jeremiah creates a prophetic indictment.', NULL),
  (47, 'And he taught daily in the temple. But the chief priests and the scribes and the chief of the people sought to destroy him,', 'Καὶ ἦν διδάσκων τὸ καθ'' ἡμέραν ἐν τῷ ἱερῷ· οἱ δὲ ἀρχιερεῖς καὶ οἱ γραμματεῖς ἐζήτουν αὐτὸν ἀπολέσαι καὶ οἱ πρῶτοι τοῦ λαοῦ,', 'Kai ēn didaskōn to kath'' hēmeran en tō hierō; hoi de archiereis kai hoi grammateis ezētoun auton apolesai kai hoi prōtoi tou laou,', '"He taught daily in the temple" (ēn didaskōn to kath'' hēmeran — he was teaching daily, a periphrastic imperfect indicating continuous daily activity) — Jesus establishes a teaching ministry in the Temple as his base of operations for chapters 20-21. "The chief priests and the scribes and the chief of the people sought to destroy him" (ezētoun auton apolesai — were seeking to destroy him; the imperfect: an ongoing sustained effort) — the same three groups who form the Sanhedrin coalition. The opposition is established as permanent and resolute; the passion is structurally inevitable from this point.', NULL),
  (48, 'And could not find what they might do: for all the people were very attentive to hear him.', 'καὶ οὐχ εὕρισκον τὸ τί ποιήσωσιν· ὁ λαὸς γὰρ ἅπας ἐξεκρέματο αὐτοῦ ἀκούων.', 'kai ouch hēuriskon to ti poiēsōsin; ho laos gar hapas exekrematō autou akouōn.', '"Could not find what they might do" (ouch heuriskon to ti poiēsōsin — were not finding what they should do; the deliberative subjunctive poiēsōsin expressing their frustrated deliberation) — the conspiracy is stalled by the people''s response. "All the people were very attentive to hear him" (ho laos gar hapas exekrematō autou akouōn — for all the people was hanging from him listening; exekremato — a striking verb: to hang suspended from something, to be riveted, to hang on every word; found only here in the NT) — the people''s riveted attention creates a protective barrier around Jesus that prevents the authorities from acting openly.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 19;
